package scalascript.imports

import scala.util.Try
import scala.jdk.CollectionConverters.*

/** `ssc-lock.yaml` — records the resolved version of every transitive dependency.
 *
 *  ```yaml
 *  # ssc-lock.yaml — generated by `ssc update`, do not edit
 *  locked:
 *    "io.scalascript/json": "1.0.0"
 *    "io.example/utils": "2.1.3"
 *  ```
 *
 *  Keys are `<org>/<name>` (no version). Generated by `ssc update`,
 *  committed to the repo, consumed during `ssc build` / `ssc run`. */
case class SscLibLock(locked: Map[String, String]):

  def withResolved(key: String, version: String): SscLibLock =
    copy(locked = locked.updated(key, version))

object SscLibLock:
  val FileName = "ssc-lock.yaml"
  val empty    = SscLibLock(Map.empty)

  def parseString(yaml: String): Try[SscLibLock] = Try {
    val raw = scalascript.parser.SimpleYaml.load[java.util.Map[String, Any]](yaml)
    val m = Option(raw)
      .map(_.asScala.toMap)
      .getOrElse(Map.empty)
    val locked: Map[String, String] =
      m.get("locked") match
        case Some(deps: java.util.Map[?, ?]) =>
          deps.asInstanceOf[java.util.Map[String, Any]].asScala
            .map((k, v) => k.toString -> v.toString).toMap
        case _ => Map.empty
    SscLibLock(locked)
  }

  def toYaml(lock: SscLibLock): String =
    val sb = new StringBuilder
    sb.append("# ssc-lock.yaml — generated by `ssc update`, do not edit\n")
    sb.append("locked:\n")
    lock.locked.toList.sortBy(_._1).foreach { (dep, ver) =>
      sb.append(s"""  "$dep": "$ver"\n""")
    }
    sb.toString

  def read(path: os.Path): Try[SscLibLock] =
    if !os.exists(path) then
      scala.util.Failure(new RuntimeException(s"$FileName not found: $path"))
    else parseString(os.read(path))

  def write(lock: SscLibLock, path: os.Path): Unit =
    os.makeDir.all(path / os.up)
    os.write.over(path, toYaml(lock))
